[SysClientCacheDataMethodAttribute(true)]
public display container displayHasTextblock()
{
    return FWFTextBlockHelper::hasTextblock(this);
}

public void  update(boolean  _dropInvent,
                    Common   _childBuffer,
                    boolean  _updateOrderLineOfDeliverySchedule,
                    boolean  _isCalledFromPSAActivityEstimates
                    )
{
    next update(_dropInvent, _childBuffer, _updateOrderLineOfDeliverySchedule, _isCalledFromPSAActivityEstimates);

    if (this.FWFTextBlockReInitRequired)
    {
        this.FWFTextBlockReInitRequired = NoYes::No;
        this.doUpdate();
    }
}
